  "totalCount": 753,
  "studies": [
    {
      "protocolSection": {
        "identificationModule": {
          "nctId": "NCT04117815",
          "orgStudyIdInfo": {
            "id": "1049/2018"
          },
          "organization": {
            "fullName": "Medical University Innsbruck",
            "class": "OTHER"
          },
          "briefTitle": "Hair-Safe Study: Scalp Cooling for Hair Saving in Women Undergoing Chemotherapy",
          "officialTitle": "Hair-Safe Study: Scalp Cooling for Hair Saving in Women Undergoing Chemotherapy"
        },
        "statusModule": {
          "statusVerifiedDate": "2022-01",
          "overallStatus": "COMPLETED",
          "expandedAccessInfo": {
            "hasExpandedAccess": false
          },
          "startDateStruct": {
            "date": "2018-05-18",
            "type": "ACTUAL"
          },
          "primaryCompletionDateStruct": {
            "date": "2020-04-30",
            "type": "ACTUAL"
          },
          "completionDateStruct": {
            "date": "2021-02-28",
            "type": "ACTUAL"
          },
          "studyFirstSubmitDate": "2019-06-17",
          "studyFirstSubmitQcDate": "2019-10-03",
          "studyFirstPostDateStruct": {
            "date": "2019-10-07",
            "type": "ACTUAL"
          },
          "lastUpdateSubmitDate": "2022-01-19",
          "lastUpdatePostDateStruct": {
            "date": "2022-01-20",
            "type": "ACTUAL"
          }
        },
        "sponsorCollaboratorsModule": {
          "responsibleParty": {
            "type": "SPONSOR"
          },
          "leadSponsor": {
            "name": "Medical University Innsbruck",
            "class": "OTHER"
          }
        },
        "oversightModule": {
          "isFdaRegulatedDrug": false,
          "isFdaRegulatedDevice": true
        },
        "descriptionModule": {
          "briefSummary": "Chemotherapy (CT) is a frequent and well established treatment in women with breast and gynecological tumors. Alopecia is one of the most common side effects of CT seriously impairing patient quality of life and body image. While other CT associated side effects can be controlled by supportive treatment strategy, adequate preventive measures for alopecia have been lacking. New evidence supports the efficacy of scalp cooling for alopecia prevention during CT.",
          "detailedDescription": "Scalp cooling using cooling caps has been identified as an effective treatment option against CT-induced alopecia in numerous European countries. Originally, crashed ice was used to cause vasoconstriction and consequently diminish CT uptake to hair follicles during CT. Soon, this method turned out impractically and has been displaced by cooling caps which allow a constant cooling of the scalp while easy handling.\n\nHowever, effectiveness of scalp cooling depends on different factors such as hair texture, chemotherapy regimen, dose of chemotherapy, cooling time, and compliance of the patient.\n\nRecent studies focused on alopecia prevention more than on patients' quality of life and satisfaction. Therefore, data on routine use of cool caps with a focus on efficiency in daily routine and patients' acceptability are missing.\n\nPatient-reported outcomes (PROs) provide results assessed by the use of a patient's report about his or her own health condition \"without amendment or interpretation by a clinician or anyone else\" and are a valuable source of information when evaluating clinical interventions or treatment toxicity in intervention studies in oncology. PROs can be perfectly used to evaluate the implication of scalp cooling regarding hair preservation but also quality of life outcome which seems even more important.\n\nWomen with breast- or gynecological cancer receiving taxane- or anthracycline-based neoadjuvant chemotherapy are included in the study. Chemotherapy can be neoadjuvant, adjuvant or palliative. Up to two lines of chemotherapy are allowed. Scalp cooling with a maintenance temperature of 17°C will be initiated 30 minutes prior to each chemotherapy cycle and stopped 90 minutes after CT. Patients are assessed for alopecia and qualitiy of life."
        },
        "conditionsModule": {
          "conditions": [
            "Breast Cancer Female",
            "Alopecia"
          ]
        },
        "designModule": {
          "studyType": "OBSERVATIONAL",
          "patientRegistry": false,
          "designInfo": {
            "observationalModel": "COHORT",
            "timePerspective": "PROSPECTIVE"
          },
          "enrollmentInfo": {
            "count": 128,
            "type": "ACTUAL"
          }
        },
        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "study group",
              "description": "Patients with breast or gynecological cancer planning to undergo chemotherapy Chemotherapy can be neoadjuvant, adjuvant or palliative Up to two lines of chemotherapy are allowed. Adjuvant therapy counts as one line.\n\nChemotherapy regime is associated with alopecia. Chemotherapy must be planned for at least 4 cycles of taxane or antracycline- based chemotherapy regimen No alopecia of any reason (up-front) No overt cognitive impairment and fluent in German Written informed consent Age 18 and older",
              "interventionNames": [
                "Device: Paxman Scalp Cooling System",
                "Other: Alopecia Assessments"
              ]
            },
            {
              "label": "reference group",
              "description": "For the purpose of comparison, a reference sample will be included in the study applying to the following inclusion criteria:\n\nPatients with breast or gynecological cancer planning to undergo chemotherapy Chemotherapy can be neoadjuvant, adjuvant or palliative Up to two lines of chemotherapy are allowed. Adjuvant therapy counts as one line.\n\nChemotherapy regime is associated with alopecia. Chemotherapy must be planned for at least 4 cycles of taxane or antracycline- based chemotherapy regimen Refuse to undergo scalp cooling Patients who have been excluded for the study group for the reason of migraine Written informed consent Age 18 and older\n\nPatients from the reference group complete the same survey as the study group. Group comparisons will be adjusted for baseline body image and reasons for refusal.",
              "interventionNames": [
                "Other: Alopecia Assessments"
              ]
            }
          ],
          "interventions": [
            {
              "type": "DEVICE",
              "name": "Paxman Scalp Cooling System",
              "description": "All patients who accomplish inclusion criteria and do not exhibit any contraindication undergo scalp cooling with the following conditions:\n\n* Minimum 30 minutes pre-infusion cooling\n* Cooling for the duration of chemotherapy infusion\n* Minimum 90 minutes post-infusion cooling Scalp cooling is performed within the study group at each CT session.",
              "armGroupLabels": [
                "study group"
              ]
            },
            {
              "type": "OTHER",
              "name": "Alopecia Assessments",
              "description": "Patients (study group and reference group) will be assessed at the following time Points:\n\n* Baseline\n* at the half-way Point of the cyles\n* at the last CT cycle\n* 3 months after completion of Treatment\n* 6-9 months after treatment completion\n\nThe assesments include the following\n\n* Photographs of the head, which are evaluated using the CTCAEv4.0\n* Questionnaire including the NCI- PRO-CTCAE-ITEMS, EORTC QLQ-C30, EORTC QLQ-B23, Body Image Scale, PRO-CTACAEs and Hairdex questionnaire",
              "armGroupLabels": [
                "reference group",
                "study group"
              ]
            }
          ]
        },
        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "Extent of hair preservation",
              "description": "Hair preservation assessed by photo documentation using VAS (Visual Analogue Scale (Grade 1: \\< 25% hair loss; Grade 2: 25-50% of hair loss; Grade 3: 50-75%)",
              "timeFrame": "on average of 15 month"
            }
          ],
          "secondaryOutcomes": [
            {
              "measure": "Assessment of Adverse Events (CTCAE 4.03)",
              "description": "CTCAE are descriptive terminology for reporting adverse events including a grading for each of these adverse events. This 5-point grading has a range from mild symptoms requiring no intervention (grade 1) to life-threatening consequences (grade 4) and finally death (grade 5)",
              "timeFrame": "on average of 15 month"
            },
            {
              "measure": "Assessment of patient satisfaction (HAIRDEX)",
              "description": "The Hairdex questionnaire is a reliable and valid instrument for the evaluation of quality of life in patients with hair diseases (i.e. validated in patients with alopecia diffusa and androgenica). Using a five-point Likert Scale (never=0 to always =4), the questionnaire encompasses 48 items composing the 5 subscales symptoms, functioning, emotionals, self-confidence and stigmatization. All scales range from 0-100, higher values indicate higher impairment.",
              "timeFrame": "on average of 15 month"
            },
            {
              "measure": "Assessment of quality of life (EORTC) QLQ-C30",
              "description": "he EORTC QLQ-C30 Aaronson is a self-report measure consisting of 30 items with a 4 point Likert Scale response format. It targets on functioning (physical, role emotional, cognitive, and social functioning and global health/QoL scale) and symptoms (fatigue, nausea and emesis, pain, dyspnoea, insomnia, appetite loss, constipation, diarrhoea, financial difficulties). All scales and single items range from 0-100.",
              "timeFrame": "on average of 15 month"
            },
            {
              "measure": "Assessment of quality of life (EORTC) BR23",
              "description": "The 23-item EORTC QLQ BR23 contains two breast cancer specific functional scales (body image and sexuality) and three symptom scales evaluating arm symptoms, breast symptoms, and systemic therapy symptoms. In addition, we include EORTC single items for hair loss.",
              "timeFrame": "on average of 15 month"
            },
            {
              "measure": "Assessment of quality of life (Body Image Scale BIS)",
