        },
        "oversightModule": {
          "oversightHasDmc": false,
          "isFdaRegulatedDrug": false,
          "isFdaRegulatedDevice": false
        },
        "descriptionModule": {
          "briefSummary": "This research is evaluating the impact of a 12-week prolonged nightly fasting (POF) and exercise intervention on metabolic markers and patient reported outcomes in women with metastatic breast cancer (MBC) initiating endocrine therapy in combination with palbociclib or alpelisib.",
          "detailedDescription": "This is single-arm feasibility pilot study exploring whether a combined prolonged nightly fasting (POF) and exercise program could impact hyperglycemia and other adverse metabolic consequences of PI3 kinase inhibitors in women with metastatic breast cancer (MBC).\n\nWomen who exercise regularly and who have lower levels of blood sugar and metabolic hormones like insulin have a lower risk of developing breast cancer. Some evidence also suggests that exercise and metabolism are related to cancer recurrence in women who are diagnosed with breast cancers that can be removed with surgery, but less is known about how exercise and metabolic factors are related to cancer progression in women whose cancer has advanced beyond the breast and underarm lymph nodes. This study is designed to look at the effects of exercise combined with prolonged nightly fasting (having a longer time between dinner and breakfast the next day), on blood sugar and hormones that control metabolism. This study looks to provide important information about whether making these kinds of changes is possible for women living with advanced breast cancer and will explore how making these changes effects blood sugar and hormone levels in women taking different kinds of treatments for advanced breast cancer.\n\nThe research study procedures include screening for eligibility, a baseline visit to collect information about diet and exercise habits, a baseline blood draw, participation in a 12-week diet and exercise program, and a follow up visit and blood collection at the end of the diet and exercise program.\n\nParticipants will be in this research study for up to 14-weeks, including the baseline and end of study visits to collect study measures.\n\nIt is expected that about 30 people will take part in this research study"
        },
        "conditionsModule": {
          "conditions": [
            "Breast Cancer",
            "Metastatic Breast Cancer"
          ],
          "keywords": [
            "Breast Cancer",
            "Metastatic Breast Cancer"
          ]
        },
        "designModule": {
          "studyType": "INTERVENTIONAL",
          "phases": [
            "NA"
          ],
          "designInfo": {
            "allocation": "NA",
            "interventionModel": "SINGLE_GROUP",
            "primaryPurpose": "SUPPORTIVE_CARE",
            "maskingInfo": {
              "masking": "NONE"
            }
          },
          "enrollmentInfo": {
            "count": 30,
            "type": "ACTUAL"
          }
        },
        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "Prolonged Nightly Fasting Plus Exercise",
              "type": "EXPERIMENTAL",
              "description": "Participants will be grouped into two cohorts determined by whether they receive palbociclib or alpelisib as part of their breast cancer treatment and then receive a 12 week prolonged nightly fasting plus exercise program consisting of:\n\n* Prolonged overnight fasting: Not consume any calorie-containing food/drinks after 8pm, waiting a minimum of 13 hours after their last meal of the day before eating the next day, target goal of fasting at least 6 days a week, daily record of first and last meals\n* Exercise Program: Coach provided at-home, personalized exercise regimen with target goal of 120 minutes of moderate-intensity aerobic activity each week as well as two 30-45-minute virtual strength training classes per week, receive fitbit for exercise and heart rate monitoring, weekly telephone-based support sessions with coach.",
              "interventionNames": [
                "Behavioral: Prolonged Nightly Fasting",
                "Behavioral: Exercise"
              ]
            }
          ],
          "interventions": [
            {
              "type": "BEHAVIORAL",
              "name": "Prolonged Nightly Fasting",
              "description": "Restriction of consumption of calorie-containing food/drinks after 8pm",
              "armGroupLabels": [
                "Prolonged Nightly Fasting Plus Exercise"
              ]
            },
            {
              "type": "BEHAVIORAL",
              "name": "Exercise",
              "description": "Personalized moderate-intensity, aerobic exercise and strength training",
              "armGroupLabels": [
                "Prolonged Nightly Fasting Plus Exercise"
              ]
            }
          ]
        },
        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "Rate of enrollment",
              "description": "The primary objective is to evaluate the feasibility of the intervention. Feasibility will be defined by the rate of enrollment and the intervention will be considered feasible if at least 80% of planned participants are enrolled within 12 months of study activation.",
              "timeFrame": "12 months"
            },
